#include "EnergyManagementSystem.h"
#include "ApiServer.h"
static ApiServer* makeApi(EnergyManagementSystem& e){ static ApiServer api(e); return &api; }
EnergyManagementSystem::EnergyManagementSystem():api_(nullptr),loads_{ Appliance(1,"Fridge",16,0x40,150,100,9.5,9.8,true), Appliance(2,"Pump",17,0x41,240,90,8.5,9.0,false), Appliance(3,"Lights",18,0x44,30,60,7.0,7.0,false), Appliance(4,"Router",19,0x45,18,80,9.0,8.0,false), Appliance(5,"Workshop",21,0x46,400,30,4.0,5.0,false)},loadCount_(5){}
void EnergyManagementSystem::begin(){ solarVoltage_.begin(); battery_.begin(); preferences_.begin(); for(uint8_t i=0;i<loadCount_;i++)loads_[i].begin(); preferences_.load(loads_, loadCount_); api_=makeApi(*this); api_->begin(); ws_.begin(); }
void EnergyManagementSystem::loop(){ unsigned long now=millis(); float dt=(lastMs_==0)?0.0f:(now-lastMs_)/3600000.0f; lastMs_=now; solar_.voltage=solarVoltage_.filteredVoltage(); solar_.current=0; solar_.power=solar_.voltage*solar_.current; float load=demand_.currentUsage(loads_,loadCount_); battery_.update(load); for(uint8_t i=0;i<loadCount_;i++)loads_[i].update(dt); PlannerDecision decisions[MAX_APPLIANCES]; uint8_t dc=planner_.plan(loads_,loadCount_,solar_,battery_.data(),decisions,MAX_APPLIANCES); for(uint8_t i=0;i<dc;i++){ for(uint8_t j=0;j<loadCount_;j++) if(loads_[j].id()==decisions[i].applianceId && !loads_[j].locked) loads_[j].setRelay(decisions[i].enabled); ws_.broadcastDecision(decisions[i]); } Recommendation recs[MAX_RECOMMENDATIONS]; uint8_t rc=recommender_.generate(solar_,battery_.data(),load,recs,MAX_RECOMMENDATIONS); for(uint8_t i=0;i<rc;i++)ws_.broadcastRecommendation(recs[i]); ws_.broadcastSensorUpdate(solar_,battery_.data()); preferences_.save(loads_, loadCount_); if(api_)api_->loop(); ws_.loop(); }
